 1→import { useState, useEffect, useRef } from "react";
 2→import { loadBlpDataUrl } from "../utils/blp";
 3→
 4→/**
 5→ * Hook to load a BLP texture and return a data URL string.
 6→ * Returns empty string while loading.
 7→ */
 8→export function useBlpTexture(path: string | undefined): string {
 9→  const [url, setUrl] = useState("");
10→  const pathRef = useRef(path);
11→
12→  useEffect(() => {
13→    if (!path) {
14→      setUrl("");
15→      return;
16→    }
17→    pathRef.current = path;
18→    let cancelled = false;
19→
20→    loadBlpDataUrl(path).then((dataUrl) => {
21→      if (!cancelled && pathRef.current === path) {
22→        setUrl(dataUrl);
23→      }
24→    }).catch(() => {
25→      if (!cancelled) setUrl("");
26→    });
27→
28→    return () => { cancelled = true; };
29→  }, [path]);
30→
31→  return url;
32→}
33→
34→/**
35→ * Hook to load multiple BLP textures in parallel.
36→ * Returns a record mapping keys to data URLs.
37→ */
38→export function useBlpTextures<K extends string>(
39→  paths: Record<K, string | undefined>,
40→): Record<K, string> {
41→  const [urls, setUrls] = useState<Record<K, string>>(() => {
42→    const init = {} as Record<K, string>;
43→    for (const key of Object.keys(paths) as K[]) {
44→      init[key] = "";
45→    }
46→    return init;
47→  });
48→
49→  useEffect(() => {
50→    let cancelled = false;
51→    const entries = Object.entries(paths) as [K, string | undefined][];
52→
53→    Promise.all(
54→      entries.map(async ([key, path]) => {
55→        if (!path) return [key, ""] as const;
56→        try {
57→          const dataUrl = await loadBlpDataUrl(path);
58→          return [key, dataUrl] as const;
59→        } catch {
60→          return [key, ""] as const;
61→        }
62→      }),
63→    ).then((results) => {
64→      if (cancelled) return;
65→      const newUrls = {} as Record<K, string>;
66→      for (const [key, dataUrl] of results) {
67→        newUrls[key] = dataUrl;
68→      }
69→      setUrls(newUrls);
70→    });
71→
72→    return () => { cancelled = true; };
73→    // eslint-disable-next-line react-hooks/exhaustive-deps
74→  }, [JSON.stringify(paths)]);
75→
76→  return urls;
77→}
