 1→import React, { useState } from "react";
 2→import { useBlpTexture } from "../hooks/useBlpTexture";
 3→import { COMMAND_BUTTON_ASSETS } from "../utils/assets";
 4→import type { CommandButtonData } from "../types";
 5→
 6→export interface CommandButtonProps extends CommandButtonData {
 7→  onClick?: () => void;
 8→  /** Show at 64px showcase size instead of 48px */
 9→  showcase?: boolean;
10→  className?: string;
11→}
12→
13→/**
14→ * In-game command card ability button with pressed, disabled,
15→ * cooldown, passive, level-up, and no-resources states.
16→ */
17→export function CommandButton({
18→  icon,
19→  disabledIcon,
20→  hotkey,
21→  label,
22→  disabled = false,
23→  passive = false,
24→  levelUp = false,
25→  noResources = false,
26→  cooldown = false,
27→  onClick,
28→  showcase = false,
29→  className,
30→}: CommandButtonProps) {
31→  const [pressed, setPressed] = useState(false);
32→  const [hovered, setHovered] = useState(false);
33→
34→  const backdropUrl = useBlpTexture(COMMAND_BUTTON_ASSETS.backdrop);
35→  const frameUrl = useBlpTexture(COMMAND_BUTTON_ASSETS.frame);
36→  const highlightUrl = useBlpTexture(COMMAND_BUTTON_ASSETS.highlight);
37→  const iconUrl = icon; //useBlpTexture(disabled ? disabledIcon : icon);
38→
39→  const classNames = [
40→    "cmd-btn",
41→    showcase && "cmd-btn--showcase",
42→    pressed && "cmd-btn--pressed",
43→    passive && "cmd-btn--passive",
44→    levelUp && "cmd-btn--levelup",
45→    noResources && "cmd-btn--no-resources",
46→    !icon && "cmd-btn-empty",
47→    className,
48→  ]
49→    .filter(Boolean)
50→    .join(" ");
51→
52→  return (
53→    <button
54→      type="button"
55→      className={classNames}
56→      onClick={onClick}
57→      disabled={disabled && !icon}
58→      onMouseEnter={() => setHovered(true)}
59→      onMouseLeave={() => {
60→        setHovered(false);
61→        setPressed(false);
62→      }}
63→      onMouseDown={() => setPressed(true)}
64→      onMouseUp={() => setPressed(false)}
65→    >
66→      {backdropUrl && (
67→        <img className="cmd-btn-backdrop" src={backdropUrl} alt="" />
68→      )}
69→      {iconUrl ? (
70→        <img className="cmd-btn-icon" src={iconUrl} alt={label ?? ""} />
71→      ) : (
72→        icon === undefined && (
73→          <div className="cmd-btn-fallback-icon" aria-hidden="true">
74→            *
75→          </div>
76→        )
77→      )}
78→      {frameUrl && <img className="cmd-btn-frame" src={frameUrl} alt="" />}
79→      <div
80→        className={`cmd-btn-highlight${hovered && !pressed ? " cmd-btn-highlight--on" : ""}`}
81→        style={{
82→          backgroundImage: highlightUrl ? `url("${highlightUrl}")` : undefined,
83→        }}
84→      />
85→      {cooldown && <div className="cmd-btn-cooldown" />}
86→      {noResources && <div className="cmd-btn-no-resources" />}
87→      {hotkey && (
88→        <span className="cmd-btn-hotkey" aria-hidden="true">
89→          {hotkey}
90→        </span>
91→      )}
92→    </button>
93→  );
94→}
