  1→import React, { useRef, useCallback, useEffect, useState } from "react";
  2→import { loadBlpImage } from "../utils/blp";
  3→import { GLUE_BUTTON_ASSETS } from "../utils/assets";
  4→
  5→export interface GlueButtonProps {
  6→  children: React.ReactNode;
  7→  onClick?: () => void;
  8→  disabled?: boolean;
  9→  /** Button width in px */
 10→  width?: number;
 11→  /** Button height in px */
 12→  height?: number;
 13→  className?: string;
 14→  hotkey?: string;
 15→}
 16→
 17→/**
 18→ * Standard login/menu screen button with tiled stone background,
 19→ * gold border, and hover glow.
 20→ */
 21→export function GlueButton({
 22→  children,
 23→  onClick,
 24→  disabled = false,
 25→  width = 260,
 26→  height = 48,
 27→  className,
 28→  hotkey,
 29→}: GlueButtonProps) {
 30→  const canvasRef = useRef<HTMLCanvasElement>(null);
 31→  const [hovered, setHovered] = useState(false);
 32→  const [pressed, setPressed] = useState(false);
 33→  const imagesRef = useRef<Record<string, HTMLImageElement>>({});
 34→
 35→  const draw = useCallback(() => {
 36→    const canvas = canvasRef.current;
 37→    if (!canvas) return;
 38→    const ctx = canvas.getContext("2d");
 39→    if (!ctx) return;
 40→
 41→    const w = canvas.width;
 42→    const h = canvas.height;
 43→    ctx.clearRect(0, 0, w, h);
 44→    ctx.imageSmoothingEnabled = false;
 45→
 46→    const imgs = imagesRef.current;
 47→    const bgKey = disabled ? "bgDisabled" : pressed ? "bgDown" : "bg";
 48→    const borderKey = disabled
 49→      ? "borderDisabled"
 50→      : pressed
 51→        ? "borderDown"
 52→        : "border";
 53→
 54→    if (imgs[bgKey]) ctx.drawImage(imgs[bgKey], 0, 0, w, h);
 55→    if (imgs[borderKey]) ctx.drawImage(imgs[borderKey], 0, 0, w, h);
 56→
 57→    if (hovered && !disabled && !pressed && imgs.highlight) {
 58→      ctx.globalCompositeOperation = "screen";
 59→      ctx.drawImage(imgs.highlight, 0, 0, w, h);
 60→      ctx.globalCompositeOperation = "source-over";
 61→    }
 62→  }, [hovered, pressed, disabled]);
 63→
 64→  useEffect(() => {
 65→    let cancelled = false;
 66→    const assets = GLUE_BUTTON_ASSETS;
 67→
 68→    Promise.all(
 69→      Object.entries(assets).map(async ([key, url]) => {
 70→        try {
 71→          const img = await loadBlpImage(url);
 72→          if (!cancelled) imagesRef.current[key] = img;
 73→        } catch {}
 74→      }),
 75→    ).then(() => {
 76→      if (!cancelled) draw();
 77→    });
 78→
 79→    return () => { cancelled = true; };
 80→  }, [draw]);
 81→
 82→  useEffect(() => { draw(); }, [draw]);
 83→
 84→  return (
 85→    <button
 86→      type="button"
 87→      className={`glue-screen-button ${className ?? ""}`}
 88→      style={{ width, height }}
 89→      onClick={onClick}
 90→      disabled={disabled}
 91→      onMouseEnter={() => setHovered(true)}
 92→      onMouseLeave={() => { setHovered(false); setPressed(false); }}
 93→      onMouseDown={() => setPressed(true)}
 94→      onMouseUp={() => setPressed(false)}
 95→    >
 96→      <canvas
 97→        ref={canvasRef}
 98→        className="glue-screen-canvas"
 99→        width={width * 2}
100→        height={height * 2}
101→      />
102→      <span>
103→        {hotkey && <span className="button-hotkey">{hotkey}</span>}
104→        {children}
105→      </span>
106→    </button>
107→  );
108→}
